define("block_graphreports/charts",["core/chartjs"],(Chart=>{const initCharts=()=>{document.querySelectorAll("canvas[data-chart]").forEach((canvas=>{if(canvas.dataset.initialized)return;try{const config=JSON.parse(canvas.dataset.chart);new Chart(canvas,config),canvas.dataset.initialized="1"}catch(error){console.error("[block_graphreports] Chart init error:",canvas.id,error)}}))};return{init:function(){"loading"===document.readyState?document.addEventListener("DOMContentLoaded",initCharts):initCharts()}}}));
